/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendEditInvoice, PurchParmTable_Num), FormControlEventType::Validated)]
public static void PurchParmTable_Num_OnValidated(FormControl sender, FormControlEventArgs e)
{    

    if(ETG_Parameters::find().ETGValidateInvoice == NoYes::Yes)
    {
        FormStringControl stringControl = sender as FormStringControl;
        str invoiceNum = stringControl.text();
        FormRun   form           = sender.formRun();            
        FormDataSource       vendInvoiceInfoTable_ds =   form.dataSource(formDataSourceStr(VendEditInvoice,VendInvoiceInfoTable)) as FormDataSource;
        VendInvoiceInfoTable    vendInvoiceInfoTable   = vendInvoiceInfoTable_ds.cursor();
        VendInvoiceInfoTable    vendInvoiceInfoTableOrg;

        select * from vendInvoiceInfoTableOrg where vendInvoiceInfoTableOrg.Num == vendInvoiceInfoTable.Num;

        if(vendInvoiceInfoTableOrg)
        {
            warning(strFmt("Invoice Number - %1 was already exist. Please enter a unique Invoice Number", invoiceNum));
        }
    }
}
